## Why This Is Asked

This question introduces a practical CGOA integration pattern not covered by prior samples: preallocated buffers, error propagation across the C-Go boundary, and concurrent calls.

## Key Concepts

- CGO memory management across FFI
- errno-based error reporting
- thread-safety and Go concurrency with goroutines
- proper freeing of C resources

## Code Example

```c
// header
#ifndef FORMAT_USER_H
#define FORMAT_USER_H
#include <stddef.h>
int format_user(char* out, size_t max, const char* name, int age);
#endif
```

```c
#include <stdio.h>
#include <errno.h>
#include "format_user.h"
int format_user(char* out, size_t max, const char* name, int age){
  if(!out || max==0) { errno=EINVAL; return -1; }
  int needed = snprintf(out, max, "User:%s,Age:%d", name, age);
  if(needed >= (int)max) { errno=ERANGE; return -1; }
  return needed;
}
```

```go
// Go binding
package main
/*
#include "format_user.h"
*/
import "C"
import (
  "fmt"
  "unsafe"
)
func FormatUser(name string, age int) (string, error) {
  buf := make([]byte, 256)
  cname := C.CString(name)
  defer C.free(unsafe.Pointer(cname))
  n := C.format_user((*C.char)(unsafe.Pointer(&buf[0])), C.size_t(len(buf)), cname, C.int(age))
  if n < 0 {
     return "", fmt.Errorf(C.GoString(C.strerror(C.errno)))
  }
  return string(buf[:n]), nil
}
```

