questions.explanation:
## Why This Is Asked

This question probes CGO callbacks from C to Go, cross-thread safe streaming, memory management between C and Go, and robust cancellation/backpressure handling in real-time data flows.

## Key Concepts

- CGO callback lifetimes across Go and C threads
- Memory management for C strings vs Go strings
- Per-stream state with context cancellation and resource cleanup
- Backpressure coordination between producers (C) and consumers (Go)

## Code Example

```c
// header.h
void log_cb(void* ctx, const char* line, size_t len);
```

```c
// stub.c (minimal sketch)
typedef void (*LogCallback)(void*, const char*, size_t);
static LogCallback global_cb = NULL;
static void* global_ctx = NULL;

void register_log_callback(LogCallback cb, void* ctx) {
    global_cb = cb;
    global_ctx = ctx;
}

void start_streaming() {
    // Simulate async log generation
    for (int i = 0; i < 5; i++) {
        if (global_cb) {
            const char* line = "Sample log line\n";
            global_cb(global_ctx, line, strlen(line));
        }
        usleep(100000); // 100ms delay
    }
}

void stop_streaming() {
    global_cb = NULL;
    global_ctx = NULL;
}
```

```go
// main.go
package main

/*
#cgo CFLAGS: -g -O2
#cgo LDFLAGS: -lpthread

#include "header.h"
#include <stdlib.h>
#include <string.h>

typedef struct {
    void* go_ctx;
    int cancelled;
} bridge_t;

static bridge_t* create_bridge(void* go_ctx) {
    bridge_t* b = malloc(sizeof(bridge_t));
    b->go_ctx = go_ctx;
    b->cancelled = 0;
    return b;
}

static void destroy_bridge(bridge_t* b) {
    free(b);
}

// Exported Go callback
extern void goLogCallback(void* go_ctx, const char* line, size_t len);

static void log_cb(void* ctx, const char* line, size_t len) {
    bridge_t* b = (bridge_t*)ctx;
    if (!b || b->cancelled) return;

    // Copy string to ensure safety
    char* copy = malloc(len + 1);
    memcpy(copy, line, len);
    copy[len] = '\0';

    goLogCallback(b->go_ctx, copy, len);
    free(copy);
}
*/
import "C"
import (
    "context"
    "fmt"
    "runtime"
    "sync"
    "time"
    "unsafe"
)

type logStream struct {
    ch    chan string
    ctx   context.Context
    cancel context.CancelFunc
    bridge *C.bridge_t
}

var (
    streams sync.Map // map[unsafe.Pointer]*logStream
)

//export goLogCallback
func goLogCallback(goCtx unsafe.Pointer, line *C.char, len C.size_t) {
    if stream, ok := streams.Load(goCtx); ok {
        ls := stream.(*logStream)
        select {
        case ls.ch <- C.GoStringN(line, C.int(len)):
        case <-ls.ctx.Done():
            // Channel blocked or context cancelled
        default:
            // Backpressure: drop if channel full
        }
    }
}

func StreamLogs(ctx context.Context) (<-chan string, error) {
    ctx, cancel := context.WithCancel(ctx)
    ch := make(chan string, 100) // Buffer for backpressure

    // Create bridge
    bridge := C.create_bridge(unsafe.Pointer(&ch))

    ls := &logStream{
        ch:     ch,
        ctx:    ctx,
        cancel: cancel,
        bridge: bridge,
    }

    streams.Store(unsafe.Pointer(&ch), ls)

    // Register callback and start streaming
    C.register_log_callback(C.LogCallback(C.log_cb), unsafe.Pointer(bridge))

    // Start cleanup goroutine
    go func() {
        <-ctx.Done()
        cleanup(ls)
    }()

    // Start streaming in background
    go C.start_streaming()

    return ch, nil
}

func cleanup(ls *logStream) {
    // Mark as cancelled
    ls.bridge.cancelled = 1

    // Stop streaming
    C.stop_streaming()

    // Close channel
    close(ls.ch)

    // Cleanup bridge
    C.destroy_bridge(ls.bridge)

    // Remove from registry
    streams.Delete(unsafe.Pointer(&ls.ch))
}

func main() {
    ctx := context.Background()

    // Demonstrate two concurrent streams
    var wg sync.WaitGroup

    for i := 0; i < 2; i++ {
        wg.Add(1)
        go func(id int) {
            defer wg.Done()

            streamCtx, cancel := context.WithTimeout(ctx, 2*time.Second)
            defer cancel()

            ch, err := StreamLogs(streamCtx)
            if err != nil {
                fmt.Printf("Stream %d error: %v\n", id, err)
                return
            }

            fmt.Printf("Stream %d starting:\n", id)
            for line := range ch {
                fmt.Printf("Stream %d: %s", id, line)
            }
            fmt.Printf("Stream %d ended\n", id)
        }(i)
    }

    wg.Wait()
    fmt.Println("All streams completed")
}
```

