```c
// implementation: log_message_fmt
#include <pthread.h>
#include <stdio.h>
static pthread_mutex_t mu = PTHREAD_MUTEX_INITIALIZER;
int log_message_fmt(const char* level, const char* msg){
  if(!level || !msg) return -1;
  pthread_mutex_lock(&mu);
  // simplified: print to stdout (no dynamic allocation here)
  printf("[%s] %s\n", level, msg);
  pthread_mutex_unlock(&mu);
  return 0;
}
```

```go
package main
/*
#include "log.h"
#include <stdlib.h>
*/
import "C"
import (
  "fmt"
  "unsafe"
)

func Log(level string, message string) error {
  cl := C.CString(level)
  cm := C.CString(message)
  defer C.free(unsafe.Pointer(cl))
  defer C.free(unsafe.Pointer(cm))
  if C.log_message_fmt(cl, cm) != 0 {
    return fmt.Errorf("logger failed")
  }
  return nil
}
```

