## Code Example
```c
// buffer.h
typedef struct Buffer Buffer;
Buffer* buffer_new(size_t capacity);
void buffer_push(Buffer* b, const char* item);
char* buffer_to_csv(Buffer* b);
void buffer_free(Buffer* b);
void free_csv(char* s);
```

```go
package main
/*
#include "buffer.h"
*/
import "C"
import (
 "errors"
 "unsafe"
)

type Buffer struct{ p *C.Buffer }

func NewBuffer(cap int) (*Buffer, error) {
 b := C.buffer_new(C.size_t(cap))
 if b == nil { return nil, errors.New("alloc failed") }
 return &Buffer{p: b}, nil
}

func (b *Buffer) Push(item string) error {
 cstr := C.CString(item)
 defer C.free(unsafe.Pointer(cstr))
 C.buffer_push(b.p, cstr)
 return nil
}

func (b *Buffer) CSV() (string, error) {
 csv := C.buffer_to_csv(b.p)
 if csv == nil { return "", errors.New("csv failed") }
 s := C.GoString(csv)
 C.free_csv(csv)
 return s, nil
}
```

