package main

/*
#cgo LDFLAGS: -lpthread
#include "logger.h"
#include <stdlib.h>
*/
import "C"
import (
	"fmt"
	"runtime"
	"sync"
	"unsafe"
)

type logger struct {
	ch     chan string
	stopCh chan struct{}
	mu     sync.Mutex
}

var globalLogger = &logger{
	ch:     make(chan string, 100),
	stopCh: make(chan struct{}),
}

//export logCallback
func logCallback(line *C.char, user unsafe.Pointer) {
	goStr := C.GoString(line)
	select {
	case globalLogger.ch <- goStr:
	default:
		// Channel full, drop the message or handle backpressure
	}
}

func StartLogger() (<-chan string, error) {
	globalLogger.mu.Lock()
	defer globalLogger.mu.Unlock()

	// Ensure we're locked to an OS thread for CGO callbacks
	runtime.LockOSThread()

	C.start_log_stream((*[0]byte)(C.logCallback), nil)
	return globalLogger.ch, nil
}

func StopLogger() {
	globalLogger.mu.Lock()
	defer globalLogger.mu.Unlock()

	C.stop_log_stream()
	runtime.UnlockOSThread()
}

func main() {
	ch, err := StartLogger()
	if err != nil {
		fmt.Printf("Error starting logger: %v\n", err)
		return
	}

	// Read 3 lines then stop
	for i := 0; i < 3; i++ {
		line := <-ch
		fmt.Printf("Received: %s\n", line)
	}

	StopLogger()
	fmt.Println("Logger stopped")
}
