/*
#cgo LDFLAGS: -ltransform
#include "transform.h"
#include <stdlib.h>
*/
import "C"
import "unsafe"

func Transform(input []byte) ([]byte, error) {
    if len(input) == 0 {
        return nil, nil
    }

    var cOutput *C.uchar
    var cOutLen C.size_t

    cInput := (*C.uchar)(unsafe.Pointer(&input[0]))
    result := C.transform(cInput, C.size_t(len(input)), &cOutput, &cOutLen)

    if result != 0 {
        cErr := C.get_last_error()
        errMsg := C.GoString(cErr)
        return nil, fmt.Errorf("transform failed: %s", errMsg)
    }

    defer C.free_output(cOutput)

    output := C.GoBytes(unsafe.Pointer(cOutput), C.int(cOutLen))
    return output, nil
}
