```go
package main

/*
#include "header.h"
*/
import "C"
import (
	"errors"
	"sync"
	"unsafe"
)

type Decoder struct {
	ctx      *C.Decoder
	frameCh  chan []byte
	closeCh  chan struct{}
	mu       sync.Mutex
	closed   bool
	errCh    chan error
}

//export frameCallback
func frameCallback(frame *C.uint8_t, w, h C.size_t, user unsafe.Pointer) {
	d := (*Decoder)(user)
	size := int(w * h * 4)
	goFrame := make([]byte, size)
	C.memcpy(unsafe.Pointer(&goFrame[0]), unsafe.Pointer(frame), C.size_t(size))

	select {
	case d.frameCh <- goFrame:
	case <-d.closeCh:
	}
}

func NewDecoder(initData []byte, cb func(frame []byte, w, h int) error) (*Decoder, error) {
	d := &Decoder{
		frameCh: make(chan []byte, 10),
		closeCh: make(chan struct{}),
		errCh:   make(chan error, 1),
	}

	cData := (*C.uint8_t)(unsafe.Pointer(&initData[0]))
	cLen := C.size_t(len(initData))

	d.ctx = C.decoder_create(cData, cLen, 
		(C.FrameCb)(C.frameCallback), 
		unsafe.Pointer(d))

	if d.ctx == nil {
		return nil, errors.New("failed to create decoder")
	}

	go func() {
		for frame := range d.frameCh {
			if err := cb(frame, 640, 480); err != nil {
				d.errCh <- err
				return
			}
		}
	}()

	return d, nil
}

func (d *Decoder) Feed(data []byte) error {
	d.mu.Lock()
	defer d.mu.Unlock()

	if d.closed {
		return errors.New("decoder closed")
	}

	cData := (*C.uint8_t)(unsafe.Pointer(&data[0]))
	cLen := C.size_t(len(data))
	C.decoder_feed(d.ctx, cData, cLen)

	select {
	case err := <-d.errCh:
		return err
	default:
		return nil
	}
}

func (d *Decoder) Close() error {
	d.mu.Lock()
	defer d.mu.Unlock()

	if d.closed {
		return nil
	}

	d.closed = true
	close(d.closeCh)
	close(d.frameCh)
	close(d.errCh)

	if d.ctx != nil {
		C.decoder_close(d.ctx)
		d.ctx = nil
	}

	return nil
}

func main() {
	var wg sync.WaitGroup

	startDecoder := func(id int, data [][]byte) {
		defer wg.Done()

		cb := func(frame []byte, w, h int) error {
			fmt.Printf("Decoder %d: frame %dx%d\n", id, w, h)
			return nil
		}

		d, err := NewDecoder([]byte("init"), cb)
		if err != nil {
			fmt.Printf("Decoder %d error: %v\n", id, err)
			return
		}
		defer d.Close()

		for _, chunk := range data {
			if err := d.Feed(chunk); err != nil {
				fmt.Printf("Decoder %d feed error: %v\n", id, err)
				return
			}
		}
	}

	// Start two decoders
	wg.Add(2)
	data1 := [][]byte{[]byte("chunk1"), []byte("chunk2")}
	data2 := [][]byte{[]byte("chunkA"), []byte("chunkB")}

	go startDecoder(1, data1)
	go startDecoder(2, data2)

	wg.Wait()
}
```

## Memory Management Notes
- C allocates temporary frames with `malloc`
- Callback copies data to Go slice before C frees the buffer
- Go manages the final slice lifecycle via garbage collector
- Decoder cleanup ensures no memory leaks via proper `Close()` calls
- Use `defer d.Close()` pattern for guaranteed resource cleanup

