## Complete Implementation

**C Header (stream.h):**
```c
typedef void (*cb_t)(int, void*);
void register_stream(cb_t cb, void* user);
void trampoline(int value, void* handle_ptr);
void unregister_stream(void);
```

**C Trampoline (stream.c):**
```c
#include "stream.h"
#include <stdint.h>

void trampoline(int value, void* handle_ptr) {
    uintptr_t handle = (uintptr_t)handle_ptr;
    // This calls back into Go via cgo.Handle
    extern void go_callback(int value, uintptr_t handle);
    go_callback(value, handle);
}
```

**Go Binding:**
```go
/*
#cgo LDFLAGS: -L. -lstream
#include "stream.h"
*/
import "C"
import "unsafe"

var activeStreams = make(map[uintptr]chan int)
var streamsMutex sync.RWMutex

//export go_callback
func go_callback(value C.int, handlePtr C.uintptr_t) {
    handle := uintptr(handlePtr)
    streamsMutex.RLock()
    if ch, exists := activeStreams[handle]; exists {
        select {
        case ch <- int(value):
        default:
            // Channel full, drop value
        }
    }
    streamsMutex.RUnlock()
}

func StartStream() (<-chan int, func()) {
    ch := make(chan int, 100)

    // Create wrapper function and handle
    done := make(chan struct{})
    handle := C.uintptr_t(C.NewHandle(done))

    streamsMutex.Lock()
    activeStreams[uintptr(handle)] = ch
    streamsMutex.Unlock()

    // Register with C trampoline
    C.register_stream((*[0]byte)(C.trampoline), unsafe.Pointer(handle))

    // Cleanup function
    cleanup := func() {
        C.unregister_stream()
        C.Delete(C.Handle(handle))

        streamsMutex.Lock()
        delete(activeStreams, uintptr(handle))
        streamsMutex.Unlock()

        close(ch)
    }

    return ch, cleanup
}

// Usage example:
func consumeStreams() {
    stream1, stop1 := StartStream()
    stream2, stop2 := StartStream()

    go func() {
        for val := range stream1 {
            fmt.Printf("Stream 1: %d\n", val)
        }
    }()

    go func() {
        for val := range stream2 {
            fmt.Printf("Stream 2: %d\n", val)
        }
    }()

    // Stop after some time
    time.Sleep(5 * time.Second)
    stop1()
    stop2()
}
```

