type EventHandler func(int)

var (
  mu       sync.Mutex
  handles  = make(map[uintptr]EventHandler)
  nextID   uintptr = 1
)

//export goEventCallback
func goEventCallback(ctx unsafe.Pointer, event C.int) {
  id := uintptr(uintptr(ctx))
  mu.Lock()
  h, ok := handles[id]
  mu.Unlock()
  if ok {
    h(int(event))
  }
}

func BindEventHandler(handler EventHandler) (func(), error) {
  mu.Lock()
  id := nextID
  nextID++
  handles[id] = handler
  mu.Unlock()

  // register C callback with context as id
  C.register_event_source((C.event_cb)(C.goEventCallback), unsafe.Pointer(uintptr(id)))

  unbind := func() {
    mu.Lock()
    delete(handles, id)
    mu.Unlock()
  }
  return unbind, nil
}
