```c
// evt.c (minimal emitter)
#include <pthread.h>
#include <unistd.h>
#include <stdlib.h>
#include "evt.h"

static struct { event_cb cb; void* ctx; } listeners[16];
static int n=0; static pthread_t t;
static int run=1;
void* emitter(void*){ int i=0; while(run){ sleep(1); for(int k=0;k<n;k++) listeners[k].cb(i, "msg", listeners[k].ctx); i++; } return NULL; }
void register_event_listener(event_cb cb, void* ctx){ if(n<16){ listeners[n++]={cb,ctx}; if(n==1) pthread_create(&t, NULL, emitter, NULL); }}
void unregister_event_listener(void* ctx){ for(int i=0;i<n;i++) if(listeners[i].ctx==ctx){ for(int j=i;j<n-1;j++) listeners[j]=listeners[j+1]; n--; break;} if(n==0) run=0; }
