func goEventCallback(event C.int, msg *C.char, ctx unsafe.Pointer) {
  if v,ok := listeners.Load(ctx); ok {
    ch := v.(chan Event)
    ch <- Event{int(event), C.GoString(msg)}
  }
}

func StartListener() chan Event {
  ch := make(chan Event, 8)
