## Code Example

```c
// pool.h
typedef void (*task_cb)(int result, void* user);
void pool_init(int nthreads);
void pool_submit(task_cb cb, void* user);
void pool_shutdown();
```

```c
// pool.c
#include "pool.h"
#include <stdlib.h>
#include <pthread.h>

typedef struct {
    task_cb cb;
    void* user;
    int data;
} task_t;

static pthread_t* threads;
static task_t* queue;
static int queue_size, head, tail, count;
static pthread_mutex_t mutex = PTHREAD_MUTEX_INITIALIZER;
static pthread_cond_t cond = PTHREAD_COND_INITIALIZER;
static int running = 1;

void* worker(void* arg) {
    while (running) {
        pthread_mutex_lock(&mutex);
        while (count == 0 && running) {
            pthread_cond_wait(&cond, &mutex);
        }
        if (!running) break;

        task_t task = queue[head];
        head = (head + 1) % queue_size;
        count--;
        pthread_mutex_unlock(&mutex);

        task.cb(task.data + 1, task.user);
    }
    return NULL;
}

void pool_init(int nthreads) {
    queue_size = 100;
    queue = malloc(queue_size * sizeof(task_t));
    threads = malloc(nthreads * sizeof(pthread_t));

    for (int i = 0; i < nthreads; i++) {
        pthread_create(&threads[i], NULL, worker, NULL);
    }
}

void pool_submit(task_cb cb, void* user) {
    pthread_mutex_lock(&mutex);
    queue[tail].cb = cb;
    queue[tail].user = user;
    tail = (tail + 1) % queue_size;
    count++;
    pthread_cond_signal(&cond);
    pthread_mutex_unlock(&mutex);
}

void pool_shutdown() {
    running = 0;
    pthread_cond_broadcast(&cond);
    for (int i = 0; i < 4; i++) {
        pthread_join(threads[i], NULL);
    }
    free(threads);
    free(queue);
}
```

```go
// pool.go
package main

/*
#cgo CFLAGS: -Wall
#include "pool.h"
*/
import "C"

import (
	"fmt"
	"sync"
	"time"
)

var (
	mu      sync.Mutex
	tasks   = make(map[C.uintptr_t]chan int)
	nextID  C.uintptr_t = 1
)

//export taskCallback
func taskCallback(result C.int, user C.uintptr_t) {
	mu.Lock()
	ch, ok := tasks[user]
	delete(tasks, user)
	mu.Unlock()

	if ok {
		ch <- int(result)
		close(ch)
	}
}

func init() {
	C.pool_init(4)
}

func SubmitTask(data int) (<-chan int, func()) {
	ch := make(chan int, 1)

	mu.Lock()
	id := nextID
	nextID++
	tasks[id] = ch
	mu.Unlock()

	C.pool_submit((*[0]byte)(C.taskCallback), C.uintptr_t(id))

	cancel := func() {
		mu.Lock()
		if ch, exists := tasks[id]; exists {
			delete(tasks, id)
			close(ch)
		}
		mu.Unlock()
	}

	return ch, cancel
}

func main() {
	defer C.pool_shutdown()

	ch1, cancel1 := SubmitTask(5)
	ch2, cancel2 := SubmitTask(10)

	go func() {
		select {
		case result := <-ch1:
			fmt.Printf("Task 1 result: %d\n", result)
		case <-time.After(time.Second):
			fmt.Println("Task 1 timeout")
		}
		cancel1()
	}()

	go func() {
		select {
		case result := <-ch2:
			fmt.Printf("Task 2 result: %d\n", result)
		case <-time.After(time.Second):
			fmt.Println("Task 2 timeout")
		}
		cancel2()
	}()

	time.Sleep(500 * time.Millisecond)
}
```

