package main
/*
#include "kv_store.h"
*/
import "C"
import (
  "errors"
  "runtime"
  "unsafe"
)
type KVStore struct{ p *C.KVStore }
func Open(path string) (*KVStore, error) { cp := C.CString(path); defer C.free(unsafe.Pointer(cp)); s := C.kv_open(cp); if s == nil { return nil, errors.New("open failed") }; v := &KVStore{p: s}; runtime.SetFinalizer(v, func(v *KVStore){ v.Close() }); return v, nil }
func (s *KVStore) Put(key, value string) error { ck := C.CString(key); cv := C.CString(value); defer C.free(unsafe.Pointer(ck)); defer C.free(unsafe.Pointer(cv)); if C.kv_put(s.p, ck, cv) != 0 { return errors.New("put failed") }; return nil }
func (s *KVStore) Get(key string) (string, error) { ck := C.CString(key); defer C.free(unsafe.Pointer(ck)); var cstr *C.char; if C.kv_get(s.p, ck, &cstr) != 0 { return "", errors.New("get failed") }; defer C.kv_free_string(cstr); return C.GoString(cstr), nil }
func (s *KVStore) Close() { if s.p != nil { C.kv_close(s.p); s.p = nil } }
