## Code Example

```c
// header: proc.h
#ifndef PROC_H
#define PROC_H
#include <stdint.h>
#include <stdlib.h>

typedef void (*progress_cb)(int pct, void* user);
void process_data_async(const uint8_t* data, size_t len, progress_cb cb, void* user);
void abort_processing(void* handle);
#endif
```

```c
// implementation: proc.c
#include "proc.h"
#include <pthread.h>
#include <unistd.h>

typedef struct {
    const uint8_t* data;
    size_t len;
    progress_cb cb;
    void* user;
    int cancelled;
    pthread_t thread;
} process_context_t;

static void* process_thread(void* arg) {
    process_context_t* ctx = (process_context_t*)arg;
    for (int i = 0; i <= 100 && !ctx->cancelled; i++) {
        usleep(10000); // simulate work
        if (ctx->cb) ctx->cb(i, ctx->user);
    }
    return NULL;
}

void process_data_async(const uint8_t* data, size_t len, progress_cb cb, void* user) {
    process_context_t* ctx = malloc(sizeof(process_context_t));
    ctx->data = data;
    ctx->len = len;
    ctx->cb = cb;
    ctx->user = user;
    ctx->cancelled = 0;
    pthread_create(&ctx->thread, NULL, process_thread, ctx);
    pthread_detach(ctx->thread);
}

void abort_processing(void* handle) {
    process_context_t* ctx = (process_context_t*)handle;
    if (ctx) ctx->cancelled = 1;
}
```

```go
// binding: proc.go
package main

/*
#cgo CFLAGS: -I.
#cgo LDFLAGS: -L. -lproc
#include "proc.h"
#include <stdint.h>

//export progressCallback
void progressCallback(int pct, void* user) {
    // This will be implemented in Go
}
*/
import "C"
import (
    "runtime"
    "sync"
    "unsafe"
)

type processor struct {
    ch    chan int
    ctx   *C.process_context_t
    mutex sync.Mutex
}

var processors = make(map[uintptr]*processor)
var processorsMutex sync.Mutex

//export progressCallback
func progressCallback(pct C.int, user unsafe.Pointer) {
    handle := uintptr(user)
    processorsMutex.Lock()
    defer processorsMutex.Unlock()

    if proc, exists := processors[handle]; exists {
        select {
        case proc.ch <- int(pct):
        default:
        }
    }
}

func ProcessData(data []byte) (<-chan int, func()) {
    ch := make(chan int, 10)
    proc := &processor{ch: ch}

    handle := C.malloc(C.size_t(unsafe.Sizeof(uintptr(0))))
    *(*uintptr)(handle) = uintptr(unsafe.Pointer(proc))

    processorsMutex.Lock()
    processors[uintptr(handle)] = proc
    processorsMutex.Unlock()

    cdata := (*C.uint8_t)(unsafe.Pointer(&data[0]))
    C.process_data_async(cdata, C.size_t(len(data)), 
        (C.progress_cb)(C.progressCallback), handle)

    cancel := func() {
        proc.mutex.Lock()
        defer proc.mutex.Unlock()

        if proc.ctx != nil {
            C.abort_processing(unsafe.Pointer(proc.ctx))
        }

        processorsMutex.Lock()
        delete(processors, uintptr(handle))
        processorsMutex.Unlock()

        C.free(handle)
        close(ch)
    }

    runtime.SetFinalizer(proc, func(*processor) {
        cancel()
    })

    return ch, cancel
}
```

```go
// main.go
package main

import (
    "fmt"
    "time"
)

func main() {
    data1 := make([]byte, 1000)
    data2 := make([]byte, 2000)

    ch1, cancel1 := ProcessData(data1)
    ch2, cancel2 := ProcessData(data2)

    go func() {
        for pct := range ch1 {
            fmt.Printf("Processor 1: %d%%\n", pct)
        }
    }()

    go func() {
        for pct := range ch2 {
            fmt.Printf("Processor 2: %d%%\n", pct)
        }
    }()

    time.Sleep(2 * time.Second)
    cancel1()

    time.Sleep(1 * time.Second)
    cancel2()

    fmt.Println("All processors stopped")
}
```

