  mu sync.Mutex
  callbacks = map[cgo.Handle]func(int, string){}
)

//export goCallbackBridge
func goCallbackBridge(status C.int, msg *C.char, user unsafe.Pointer) {
  h := cgo.Handle(user)
  mu.Lock(); cb := callbacks[h]; mu.Unlock()
  if cb != nil {
    cb(int(status), C.GoString(msg))
  }
}

func StartEngine(cb func(int, string)) {
  h := cgo.NewHandle(cb)
  mu.Lock(); callbacks[h] = cb; mu.Unlock()
  C.start_engine((*[0]byte)(unsafe.Pointer(C.goCallbackBridge)), unsafe.Pointer(h))
}
